customCSS:
/* Wood Paneling - Polished Walnut */
@import url('https://fonts.googleapis.com/css2?family=Libre+Baskerville:wght@400;700&family=Source+Sans+3:wght@300;400;600&family=Source+Code+Pro&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 600px 400px at 30% 10%, rgba(245, 168, 24, 0.1), transparent),
    radial-gradient(ellipse 500px 350px at 70% 90%, rgba(200, 144, 64, 0.07), transparent);
}

.cyber-particles { display: none; }

.stat-card {
  border: 1px solid rgba(200, 144, 64, 0.22);
  background: rgba(51, 34, 12, 0.9);
}

.stat-card::before {
  background: linear-gradient(90deg, #c89040, #e8b830, #f5a818);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(232, 184, 48, 0.4);
  box-shadow: 0 4px 20px rgba(245, 168, 24, 0.15);
}

.stat-value {
  text-shadow: none;
}

.celebration-title {
  color: #f0d050 !important;
  text-shadow: 0 0 20px rgba(240, 208, 80, 0.5);
}

.miner-card, .health-card, .lifetime-card {
  background: rgba(51, 34, 12, 0.7);
  border: 1px solid rgba(200, 144, 64, 0.14);
}

.miner-card:hover {
  border-color: rgba(232, 184, 48, 0.3);
}
